class Solution {
public:
    int maxScore(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        int n = nums.size() / 2;
        int res = 0;
        for (int i = n - 1; i >= 0; i--) {
            int j = i + 1;
            while (j < n && nums[i] % nums[j] == 0) {
                res += (i + 1) * nums[i];
                j++;
            }
            i = j - 1;
        }
        return res;
    }
};
```

